(function(){'use strict';const CONFIG={breakpoint:736,closeOnLinkClick:true,...((window.CarrdPluginOptions&&window.CarrdPluginOptions.headerNav)||{})};const HEADER_SELECTOR='#header';const COLLAPSING_SELECTOR='.header-mobile-hide, .header-mobile-el-collapsing';const CLASSNAMES={open:'is-nav-open',primarySection:'theme-header-nav-primary-section',toggle:'theme-header-nav-toggle',toggleBar:'theme-header-nav-toggle-bar'};const INSTANCES=[];const POSITION_INSTANCES=[];let globalsBound=false;function createToggle(){const button=document.createElement('button');button.type='button';button.className=CLASSNAMES.toggle;button.setAttribute('aria-label','Toggle navigation');button.setAttribute('aria-expanded','false');for(let i=0;i<3;i+=1){const bar=document.createElement('span');bar.className=CLASSNAMES.toggleBar;button.appendChild(bar);}return button;}function climbToCell(marked,inner){let cell=marked;while(cell&&cell!==inner&&cell.parentElement!==inner){cell=cell.parentElement;}return cell&&cell.parentElement===inner?cell:null;}function resolvePrimarySection(header){const inner=header.querySelector('.wrapper > .inner')||header.querySelector('.inner')||header.querySelector('.wrapper')||header;const marked=header.querySelector('#header-primary-section');if(marked&&inner.contains(marked)){return climbToCell(marked,inner)||marked;}return inner.firstElementChild||inner;}function bindGlobals(){if(globalsBound||(!INSTANCES.length&&!POSITION_INSTANCES.length))return;globalsBound=true;let resizeTimer;window.addEventListener('resize',()=>{clearTimeout(resizeTimer);resizeTimer=setTimeout(()=>{INSTANCES.forEach(i=>i.onResize());POSITION_INSTANCES.forEach(i=>i.sync());},60);});document.addEventListener('keydown',event=>{if(event.key!=='Escape')return;INSTANCES.forEach(i=>{if(i.isOpen())i.close(true);});});}function applyToggleTopAttribute(header){const source=header.querySelector(':scope > [data-header-nav-toggle-top]')||(header.hasAttribute('data-header-nav-toggle-top')?header:null);if(!source)return;const raw=source.getAttribute('data-header-nav-toggle-top');if(raw===null||raw.trim()==='')return;const text=raw.trim();let value=null;if(/^-?\d*\.?\d+$/.test(text)){value=text+'rem';}else if(/^-?\d*\.?\d+(px|rem|em|vh|vw|%)$/.test(text)){value=text;}if(value)header.style.setProperty('--theme-header-nav-toggle-top',value);}function initializeHeader(header){if(header.getAttribute('data-header-nav-bound')==='true')return;if(!header.querySelector(COLLAPSING_SELECTOR))return;header.setAttribute('data-header-nav-bound','true');applyToggleTopAttribute(header);const primarySection=resolvePrimarySection(header);primarySection.classList.add(CLASSNAMES.primarySection);const toggle=header.querySelector('.'+CLASSNAMES.toggle)||createToggle();if(toggle.parentNode!==primarySection){primarySection.appendChild(toggle);}const isMobile=()=>window.innerWidth<=CONFIG.breakpoint;const revealHeader=()=>{const reduceMotion=window.matchMedia&&window.matchMedia('(prefers-reduced-motion: reduce)').matches;if(header.getBoundingClientRect().top<0){header.scrollIntoView({behavior:reduceMotion?'auto':'smooth',block:'start'});}};const setOpen=(open,options)=>{options=options||{};header.classList.toggle(CLASSNAMES.open,open);toggle.setAttribute('aria-expanded',open?'true':'false');if(open&&isMobile())revealHeader();if(!open&&options.restoreFocus)toggle.focus();};const onResize=()=>{if(!isMobile())setOpen(false);};toggle.addEventListener('click',()=>{if(!isMobile())return;const open=header.classList.contains(CLASSNAMES.open);if(open&&header.getBoundingClientRect().top<0){revealHeader();return;}setOpen(!open);});if(CONFIG.closeOnLinkClick){header.addEventListener('click',event=>{if(!isMobile())return;const link=event.target.closest('a');if(link&&header.contains(link))setOpen(false);});}INSTANCES.push({onResize:onResize,isOpen:()=>header.classList.contains(CLASSNAMES.open),close:restoreFocus=>setOpen(false,{restoreFocus:restoreFocus})});onResize();}function applyOffsetAttribute(header,target){const raw=target.getAttribute('data-header-nav-fixed-offset');if(raw===null||raw.trim()==='')return;const text=raw.trim();let value=null;if(/^-?\d*\.?\d+$/.test(text)){value=text+'rem';}else if(/^-?\d*\.?\d+(px|rem|em|vh|vw|%)$/.test(text)){value=text;}if(value)header.style.setProperty('--theme-header-nav-fixed-offset',value);}function initializeHeaderPosition(header){if(header.getAttribute('data-header-position-bound')==='true')return;const target=header.querySelector(':scope > [data-header-position]')||(header.hasAttribute('data-header-position')?header:null);if(!target)return;const mode=(target.getAttribute('data-header-position')||'').trim();if(mode!=='fixed'&&mode!=='sticky')return;header.setAttribute('data-header-position-bound','true');applyOffsetAttribute(header,target);const resolveOffsetPx=()=>{let raw='';try{raw=window.getComputedStyle(target).getPropertyValue('--theme-header-nav-fixed-offset').trim();}catch(error){raw='';}if(!raw||parseFloat(raw)===0)return 0;const probe=document.createElement('div');probe.style.cssText='position:absolute;visibility:hidden;pointer-events:none;height:'+raw;header.appendChild(probe);const px=probe.offsetHeight;probe.remove();return px||0;};const sync=()=>{const offsetPx=resolveOffsetPx();let pinnedHeight;if(mode==='sticky'){const above=target.getBoundingClientRect().top-header.getBoundingClientRect().top;const aboveOffset=Math.max(0,Math.round(above));header.style.setProperty('--theme-header-nav-sticky-top',(offsetPx-aboveOffset)+'px');pinnedHeight=target.getBoundingClientRect().height;}else{pinnedHeight=header.getBoundingClientRect().height;}if(!header.classList.contains(CLASSNAMES.open)){document.documentElement.style.scrollPaddingTop=Math.round(pinnedHeight+offsetPx)+'px';}};sync();window.addEventListener('load',sync,{once:true});POSITION_INSTANCES.push({sync:sync});}function init(){document.querySelectorAll(HEADER_SELECTOR).forEach(header=>{initializeHeader(header);initializeHeaderPosition(header);});bindGlobals();}if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',init);}else{init();}})();